 80→      url: window.location.href,
 81→    };
 82→
 83→    try {
 84→      if (navigator.share) {
 85→        await navigator.share(shareData);
 86→      } else {
 87→        await navigator.clipboard.writeText(window.location.href);
 88→        alert('Lien du rapport copié dans le presse-papier !');
